    max-width: 140px;
}
#profileModal .profile-avatar-preview {
    width: 100px !important;
    height: 100px !important;
    border-radius: 50% !important;
    overflow: hidden !important;
    display: flex !important;
    align-items: center;
    justify-content: center;
    background: #f1f5f9;
    flex-shrink: 0;
    border: 2px solid #e2e8f0;
}
#profileModal #avatarPreview {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover !important;
    border-radius: 50%;
    display: block;
}
#profileModal .profile-form-section {
    flex: 1;
    min-width: 0;
    overflow: hidden;
}
/* Per-field error messages */
.pf-field-error {
    color: #ef4444;
    font-size: 0.78rem;
    font-weight: 500;
    min-height: 16px;
    line-height: 1.3;
    margin-top: 2px;
    padding-left: 2px;
    word-break: break-word;
}
.pf-field-error:empty {
    min-height: 0;
    margin: 0;
}
/* Input error state */
.pf-input-error {
    border-color: #ef4444 !important;
    box-shadow: 0 0 0 2px rgba(239,68,68,0.15) !important;
}
/* Responsive: stack on small screens */
@media (max-width: 580px) {
    #profileModal .profile-modal-body {
        flex-direction: column;
        align-items: center;
    }
    #profileModal .profile-avatar-section {
        max-width: 100%;
        flex-direction: row;
